import React from 'react';
import Clock from './Clock';
import logo from '../images/logo.png';

function Sidebar({ activePage, setActivePage, isOpen, setIsOpen }) {
  const menuItems = [
    { id: 'home', label: 'Home' },
    { id: 'about', label: 'About Indus' },
    { id: 'programs', label: 'Programs' },
    { id: 'institutes', label: 'Institutes' },
    { id: 'map', label: 'Campus Map' },
    { id: 'events', label: 'Events' },
  ];

  const handleNavigate = (id) => {
    setActivePage(id);
    setIsOpen(false);
  };

  return (
    <>
      <aside 
        className={`fixed inset-y-0 left-0 z-50 w-64 bg-sidebar-bg p-8 flex flex-col justify-between border-r border-gray-200 transition-transform duration-300 md:relative md:translate-x-0 ${
          isOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
      >
        <div>
          <div className="mb-10 flex flex-col items-center">
            {/* Logo Image Placeholder - User needs to provide logo.png in public folder */}
            <img src="Using_React\src\images\logo.png" alt="Indus University Logo" className="w-full h-auto mb-2 invert brightness-0" />
            <div className="text-xs text-white/70 italic">Where Practice Meets Theory</div>
          </div>

          <ul className="space-y-2">
            {menuItems.map((item) => (
              <li
                key={item.id}
                className={`p-4 rounded-xl cursor-pointer transition-colors duration-200 font-medium ${
                  activePage === item.id 
                    ? 'bg-white/20 text-white shadow-sm' 
                    : 'text-white/70 hover:bg-white/10 hover:text-white'
                }`}
                onClick={() => handleNavigate(item.id)}
              >
                {item.label}
              </li>
            ))}
          </ul>
        </div>

        <Clock />
      </aside>

      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 z-40 bg-black/40 backdrop-blur-sm transition-opacity md:hidden" 
          onClick={() => setIsOpen(false)}
        ></div>
      )}
    </>
  );
}

export default Sidebar;
